  static MWL_FILTER_SCHEMA(institutions, hidden, mwlLabels) {
    let filters = [];
    if (hidden) {
      filters = [{
        tag: "p-calendar",
        filterKey: "PatientBirthDate",
        description: "Patient's Birth Date"
      }, {
        tag: "select",
        options: [new SelectDropdown("F", "Female"), new SelectDropdown("M", "Male"), new SelectDropdown("O", "Other")],
        showStar: true,
        filterKey: "PatientSex",
        description: "Patient's Sex",
        placeholder: "Patient's Sex"
      }, {
        tag: "select",
        options: [new SelectDropdown("UNVERIFIED", "UNVERIFIED", "Patient not verified against any Patient Demographics Query Provider"), new SelectDropdown("VERIFIED", "VERIFIED", "Patient verified against a Patient Demographics Query Provider"), new SelectDropdown("NOT_FOUND", "NOT_FOUND", "Patient verification against a Patient Demographics Query Provider resulted in no patient found"), new SelectDropdown("VERIFICATION_FAILED", "VERIFICATION_FAILED", "Patient verification against a Patient Demographics Query Provider failed")],
        showStar: true,
        filterKey: "patientVerificationStatus",
        description: "Verification Status",
        placeholder: "Verification Status"
      }, {
        tag: "person-name-picker",
        filterKey: "ResponsiblePerson",
        placeholder: "Responsible Person",
        description: "Name of person with medical or welfare decision making authority for the Patient, typically if the Patient is a non-human organism."
      }, {
        tag: "select",
        filterKey: "includedefaults",
        showStar: true,
        options: [new SelectDropdown("true", "YES"), new SelectDropdown("false", "NO")],
        placeholder: "Include Defaults",
        description: "Enable to return only the attributes specified by Query Parameter 'includefield' without including the default set of attributes specified by DICOM Part 18"
      }];
    } else {
      filters = [{
        tag: "person-name-picker",
        filterKey: "PatientName",
        placeholder: "Patient family name",
        description: "Order of name components in the search field differs from the rendered person names in the list"
      }, {
        tag: "checkbox",
        filterKey: "fuzzymatching",
        text: "Fuzzy Matching",
        description: "Fuzzy semantic matching of person names"
      }, {
        tag: "issuer-selector",
        issuers: [{
          key: "PatientID",
          label: "Patient ID"
        }, {
          key: "IssuerOfPatientID",
          label: "Issuer of Patient ID"
        }, {
          key: "IssuerOfPatientIDQualifiersSequence.UniversalEntityID",
          label: "Issuer of Patient ID Qualifiers Sequence - Universal Entity ID"
        }, {
          key: "IssuerOfPatientIDQualifiersSequence.UniversalEntityIDType",
          label: "Issuer of Patient ID Qualifiers Sequence - Universal Entity ID Type"
        }],
        id: "PatientID",
        description: "Patient Identifier",
        placeholder: "Patient Identifier"
      }, {
        tag: "issuer-selector",
        issuers: [{
          key: "AccessionNumber",
          label: "Accession Number"
        }, {
          key: "IssuerOfAccessionNumberSequence.LocalNamespaceEntityID",
          label: "Local Namespace Entity ID"
        }, {
          key: "IssuerOfAccessionNumberSequence.UniversalEntityID",
          label: "Universal Entity ID"
        }, {
          key: "IssuerOfAccessionNumberSequence.UniversalEntityIDType",
          label: "Universal Entity ID Type"
        }],
        description: "Accession Number & Issuer of Accession Number Sequence",
        placeholder: "Accession Number & Issuer of Accession Number Sequence"
      }, {
        tag: "issuer-selector",
        issuers: [{
          key: "AdmissionID",
          label: "Admission ID"
        }, {
          key: "IssuerOfAdmissionIDSequence.LocalNamespaceEntityID",
          label: "Local Namespace Entity ID"
        }, {
          key: "IssuerOfAdmissionIDSequence.UniversalEntityID",
          label: "Universal Entity ID"
        }, {
          key: "IssuerOfAdmissionIDSequence.UniversalEntityIDType",
          label: "Universal Entity ID Type"
        }],
        description: "Admission ID & Issuer of Admission ID Sequence",
        placeholder: "Admission ID & Issuer of Admission ID Sequence"
      }, this.getInstitutionFilterSchemaElement(institutions), {
        tag: "input",
        type: "text",
        filterKey: "StudyInstanceUID",
        description: "Study Instance UID",
        placeholder: "Study Instance UID"
      }, {
        tag: "editable-multi-select",
        type: "text",
        optionsTree: [{
          options: Object.keys(this.MODALITIES.common).map(key => new SelectDropdown(key, `${key} - ${this.MODALITIES.common[key]}`))
        }, {
          options: Object.keys(this.MODALITIES.more).map(key => new SelectDropdown(key, `${key} - ${this.MODALITIES.more[key]}`))
        }],
        filterKey: "ScheduledProcedureStepSequence.Modality",
        placeholder: "Modality"
      }, {
        tag: "input",
        type: "text",
        filterKey: "ScheduledProcedureStepSequence.ScheduledStationAETitle",
        description: "Scheduled Station AE Title",
        placeholder: "Scheduled Station AE Title"
      }, {
        tag: "select",
        type: "text",
        filterKey: "ScheduledProcedureStepSequence.ScheduledProcedureStepStatus",
        options: [new SelectDropdown("STARTED", "STARTED"), new SelectDropdown("ARRIVED", "ARRIVED"), new SelectDropdown("READY", "READY"), new SelectDropdown("DEPARTED", "DEPARTED"), new SelectDropdown("SCHEDULED", "SCHEDULED"), new SelectDropdown("COMPLETED", "COMPLETED"), new SelectDropdown("CANCELED", "CANCELED"), new SelectDropdown("DISCONTINUED", "DISCONTINUED")],
        showStar: true,
        description: "SPS Status",
        placeholder: "SPS Status"
      }, {
        tag: "person-name-picker",
        filterKey: "ScheduledProcedureStepSequence.ScheduledPerformingPhysicianName",
        description: "Order of name components in the search field differs from the rendered person names in the list",
        placeholder: "SP Physician's family name"
      }, {
        tag: "range-picker",
        type: "text",
        filterKey: "ScheduledProcedureStepSequence.ScheduledProcedureStepStartDate",
        description: "SPS Start Date",
        placeholder: "Scheduled Procedure Step Start Date",
        onlyDate: true
      }, {
        tag: "range-picker-time",
        type: "text",
        filterKey: "ScheduledProcedureStepSequence.ScheduledProcedureStepStartTime",
        description: "SPS Start Time",
        placeholder: "Scheduled Procedure Step Start Time"
      }, {
        tag: "select",
        filterKey: "includefield",
        showSelectedEmptyValue: true,
        options: [new SelectDropdown("", "dicom", "Search Response Payload according DICOM PS 3.18"), new SelectDropdown("all", "All", "all available attributes")],
        description: "Include field",
        placeholder: "Include field"
      }, {
        tag: "input",
        type: "number",
        filterKey: "limit",
        description: "Limit",
        placeholder: "Limit of MWL"
      }, {
        tag: "select",
        type: "text",
        filterKey: "StudyStatusID",
        options: [new SelectDropdown("NONE", "NONE"), new SelectDropdown("CREATED", "CREATED"), new SelectDropdown("SCHEDULED", "SCHEDULED"), new SelectDropdown("ARRIVED", "ARRIVED"), new SelectDropdown("STARTED", "STARTED"), new SelectDropdown("COMPLETED", "COMPLETED"), new SelectDropdown("VERIFIED", "VERIFIED"), new SelectDropdown("READ", "READ"), new SelectDropdown("CANCELLED", "CANCELLED")],
        showStar: true,
        description: "Study Status ID - AGFA",
        placeholder: "Study Status ID - AGFA"
      }];
      if (mwlLabels) {
        filters.push({
          tag: "select",
          type: "text",
          filterKey: "WorklistLabel",
          options: mwlLabels.map(label => new SelectDropdown(label, label)),
          showStar: true,
          description: "Worklist Label",
          placeholder: "Worklist Label"
        });
      } else {
        filters.push({
          tag: "input",
          type: "text",
          filterKey: "WorklistLabel",
          description: "Worklist Label",
          placeholder: "Worklist Label"
        });
      }
    }
    return filters;
  }
